/*
=========================================================
SINGLE ITEM PICKER & CLEANER
- Sucht den ersten Eintrag, der noch nicht 'processed'='ok' ist
- Reinigt alle Felder dieses Eintrags
- Bereitet den Kontext-String für das LLM vor
=========================================================
*/

// KONFIGURATION
const statusFieldName = 'processed'; // Deine Kontrollspalte
const targetStatus = 'ok';           // Der Wert, den erledigte Zeilen haben

// Felder, die wir NICHT im Prompt wollen (technisches Zeug)
const excludedFromPrompt = [
    "processed", 
    "SO URL", 
    "API URL", 
    "Image URL", 
    "Bildlink", 
    "ID",
    "row_scan",
    "_id",
    statusFieldName // Die Kontrollspalte selbst auch nicht
];

// 1. Input holen
const items = $input.all();
let targetItem = null;

// 2. SEARCH LOOP: Finde das erste "offene" Item
for (const item of items) {
    const currentStatus = item.json[statusFieldName];

    // Bedingung: Wenn Status leer ist ODER ungleich 'ok'
    if (!currentStatus || currentStatus !== targetStatus) {
        targetItem = item;
        break; // WICHTIG: Sofort stoppen, wir wollen nur einen!
    }
}

// Wenn alle schon erledigt sind ("ok"), geben wir nichts zurück -> Workflow stoppt hier meist
if (!targetItem) {
    return [];
}

// -------------------------------------------------------
// AB HIER: Reinigung nur für das gefundene targetItem
// -------------------------------------------------------

// Hilfsfunktion: Text reinigen
function cleanText(text) {
    if (text === null || text === undefined) return "Keine Angabe";
    let cleaned = String(text);
    cleaned = cleaned.replace(/[\u200B\u00A0]/g, ' '); // Zero Width Spaces weg
    return cleaned.trim();
}

const originalJson = targetItem.json;
const cleanJson = {};
let contextLines = [];

// Dynamisch über ALLE Spalten iterieren
for (const key of Object.keys(originalJson)) {
    const rawValue = originalJson[key];

    // Wert reinigen
    const cleanValue = cleanText(rawValue);

    // In das saubere JSON-Objekt speichern
    cleanJson[key] = cleanValue;

    // Entscheiden, ob es in den Kontext-String kommt
    if (cleanValue !== "Keine Angabe" && cleanValue !== "" && !excludedFromPrompt.includes(key)) {
        contextLines.push(`${key}: ${cleanValue}`);
    }
}

// Den Context-String zusammenbauen
const contextString = contextLines.join('\n');

// Daten in das Item schreiben
targetItem.json.metadata_clean = cleanJson; 
targetItem.json.context_data_string = contextString; 

// WICHTIG: Wir geben ein Array zurück, das NUR dieses eine Item enthält
return [targetItem];
